     1→import type moment from 'moment';
     2→import type { MyOrdersDetailProps, TransactionType } from './Models';
     3→
     4→export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     5→
     6→export const getTransactionGainType = (
     7→  transaction: MyOrdersDetailProps['transaction'],
     8→): TransactionGainType => {
     9→  if (!transaction) return 'CARD';
    10→
    11→  const provider = transaction.details?.provider?.toLowerCase() || '';
    12→
    13→  if (provider.includes('cashback')) {
    14→    return 'CASHBACK';
    15→  }
    16→
    17→  const icon = transaction.icon?.toLowerCase() || '';
    18→  const description = transaction.description?.toLowerCase() || '';
    19→
    20→  const tagIndicators = [
    21→    'tag',
    22→    'pedágio',
    23→    'pedagio',
    24→    'estacionamento',
    25→    'abastecimento',
    26→    'abastece',
    27→    'drive',
    28→    'lava',
    29→    'rápido',
    30→  ];
    31→
    32→  const isTag = tagIndicators.some(
    33→    indicator =>
    34→      icon.includes(indicator) ||
    35→      description.includes(indicator) ||
    36→      provider.includes(indicator),
    37→  );
    38→
    39→  return isTag ? 'TAG' : 'CARD';
    40→};
    41→
    42→export const getFormattedPointsValue = (
    43→  amount: number,
    44→  type: TransactionType,
    45→): string => {
    46→  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
    47→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
    48→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
    49→};
    50→
    51→export const getFormattedHighlightText = (
    52→  date: string,
    53→  _gainType: TransactionGainType,
    54→  momentInstance: typeof moment,
    55→): string => {
    56→  const transactionDate = momentInstance(date);
    57→  const day = transactionDate.format('DD');
    58→  const month = transactionDate.format('MMM').toLowerCase();
    59→  const year = transactionDate.format('YYYY');
    60→  const time = transactionDate.format('HH:mm');
    61→
    62→  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
    63→};
    64→
    65→export const getFormattedPointsValueForMarketplace = (
    66→  valuePoints: number,
    67→): string => {
    68→  const absValue = Math.abs(valuePoints);
    69→  const label = absValue === 1 ? 'ponto' : 'pontos';
    70→  return `${absValue.toLocaleString('pt-BR')} ${label}`;
    71→};
    72→
    73→export const getPaymentTypeLabel = (paymentType: string): string => {
    74→  const labels: Record<string, string> = {
    75→    POINTS: 'Pontos',
    76→    CARD: 'Cartão',
    77→    PIX: 'PIX',
    78→  };
    79→  return labels[paymentType] || paymentType;
    80→};
    81→
    82→export const getMarketplaceTitle = (
    83→  transaction: MyOrdersDetailProps['transaction'],
    84→): string | null => {
    85→  if (!transaction?.marketplace?.orders) return null;
    86→
    87→  const allItems: Array<{ name: string }> = [];
    88→  transaction.marketplace.orders.forEach(order => {
    89→    if (order.items) {
    90→      allItems.push(...order.items);
    91→    }
    92→  });
    93→
    94→  if (allItems.length === 0) return null;
    95→  if (allItems.length === 1) return allItems[0].name;
    96→
    97→  const firstItemName = allItems[0].name;
    98→  const secondItemFirstWord = allItems[1].name.split(' ')[0];
    99→
   100→  if (allItems.length === 2) {
   101→    return `${firstItemName} e ${secondItemFirstWord}`;
   102→  }
   103→
   104→  const remainingCount = allItems.length - 2;
   105→  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
   106→};
   107→
   108→export const getCleanedImageUrl = (
   109→  url: string | undefined,
   110→): string | undefined => {
   111→  if (!url) return undefined;
   112→
   113→  let cleanedUrl = url.trim();
   114→
   115→  if (cleanedUrl.startsWith('imageUrl:')) {
   116→    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
   117→  }
   118→
   119→  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
   120→    return cleanedUrl;
   121→  }
   122→
   123→  return undefined;
   124→};
